diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..98b2cad736a9 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2029,6 +2029,43 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C-(and (C3-X), C2) --> (C-(C2&C3)) + (X&C2) when:
+    // (C3 - (C2 & C3) + 1) is pow2
+    // ((C2 + C3) & ((C2 & C3) - 1)) == ((C2 & C3) - 1)
+    Constant *C2C, *C3C;
+    if (match(Op1, m_OneUse(m_And(m_OneUse(m_Sub(m_ImmConstant(C3C), m_Value(X))),
+                                  m_ImmConstant(C2C))))) {
+      // Get the scalar values (splat if vector)
+      const APInt *C2Val = nullptr;
+      const APInt *C3Val = nullptr;
+      if (auto *CI = dyn_cast<ConstantInt>(C2C))
+        C2Val = &CI->getValue();
+      else if (auto *CV = dyn_cast<Constant>(C2C); CV && CV->getType()->isVectorTy())
+        if (auto *CI = dyn_cast_or_null<ConstantInt>(CV->getSplatValue()))
+          C2Val = &CI->getValue();
+      if (auto *CI = dyn_cast<ConstantInt>(C3C))
+        C3Val = &CI->getValue();
+      else if (auto *CV = dyn_cast<Constant>(C3C); CV && CV->getType()->isVectorTy())
+        if (auto *CI = dyn_cast_or_null<ConstantInt>(CV->getSplatValue()))
+          C3Val = &CI->getValue();
+      const APInt *CVal;
+      if (C2Val && C3Val && match(Op0, m_APInt(CVal))) {
+        APInt C2C3 = *C2Val & *C3Val;
+        APInt C3MinusC2C3Plus1 = *C3Val - C2C3 + 1;
+        APInt C2PlusC3 = *C2Val + *C3Val;
+        APInt C2C3Minus1 = C2C3 - 1;
+        if (C3MinusC2C3Plus1.isPowerOf2() &&
+            (C2PlusC3 & C2C3Minus1) == C2C3Minus1) {
+          Value *And = Builder.CreateAnd(X, C2C);
+          APInt NewC = *CVal - C2C3;
+          if (NewC.isZero())
+            return replaceInstUsesWith(I, And);
+          return BinaryOperator::CreateAdd(And,
+                                           ConstantInt::get(I.getType(), NewC));
+        }
+      }
+    }
   }

   const APInt *Op0C;

